import type React from 'react';
import { createContext, useContext, useContextSelector } from 'use-context-selector';
import { createContextHook } from '@universe-design/react-utilities';

interface AnchorContextProps {
  registerLink: (
    href: string,
    payload: {
      ref: React.RefObject<HTMLAnchorElement | null>;
    },
  ) => void;
  unregisterLink: (href: string) => void;
  activeLink: string | undefined;
  handleLinkClick: (e: React.MouseEvent<HTMLAnchorElement>, link: { title: React.ReactNode; href: string }) => void;
}

const { Provider: AnchorContextProvider, useContext: useAnchorContext } = createContextHook<AnchorContextProps>(
  'AnchorContext',
  {
    strict: true,
    customizedContextMethods: {
      createContext,
      useContext,
      useContextSelector,
    },
  },
);

export type { AnchorContextProps };
export { AnchorContextProvider, useAnchorContext };
